// src/agentic/manifestor/SelfManifestor.cpp
// Scans build directory, generates capability manifest

void SelfManifestor::scanBuildDirectory(const char* path) {
    for (auto& entry : fs::directory_iterator(path)) {
        if (entry.path().extension() == ".dll" || 
            entry.path().extension() == ".exe") {
            
            auto pe = PEParser::load(entry.path());
            
            // Look for capability exports
            for (auto& exp : pe.exports()) {
                if (exp.name.starts_with("capability_")) {
                    CapabilityManifest cap;
                    cap.name = exp.name.substr(11);
                    cap.version = exp.ordinal;
                    cap.path = entry.path();
                    cap.factory = exp.address;
                    capabilities_.push_back(cap);
                }
            }
        }
    }
    
    // Generate wiring diagram
    generateWiringDiagram("wiring_diagram.json");
}
